import random, dataclasses

@dataclasses.dataclass
class SamplingDecision:
    record: bool
    reason: str

class TailSampler:
    """
    Buffers spans in memory during a trace and decides at the end
    whether to flush them to the backend.
    """

    def __init__(
        self,
        base_rate: float = 0.05,        # keep 5% of successful traces
        error_rate: float = 1.0,         # always keep errors
        slow_threshold_ms: float = 5000, # keep traces slower than 5s
    ):
        self.base_rate = base_rate
        self.error_rate = error_rate
        self.slow_threshold_ms = slow_threshold_ms

    def decide(self, has_error: bool, total_duration_ms: float) -> SamplingDecision:
        if has_error:
            return SamplingDecision(record=True, reason="error")
        if total_duration_ms > self.slow_threshold_ms:
            return SamplingDecision(record=True, reason="slow")
        if random.random() < self.base_rate:
            return SamplingDecision(record=True, reason="sampled")
        return SamplingDecision(record=False, reason="dropped")

class BufferedTracer:
    """Buffers spans until the root span finishes, then samples."""

    def __init__(self, sampler: TailSampler, backend_flush=None):
        self.sampler = sampler
        self.buffer: list[dict] = []
        self.backend_flush = backend_flush or (lambda spans: print(f"Flushed {len(spans)} spans"))

    def record(self, span: dict) -> None:
        self.buffer.append(span)

    def finish_trace(self, has_error: bool, total_duration_ms: float) -> None:
        decision = self.sampler.decide(has_error, total_duration_ms)
        if decision.record:
            self.backend_flush(self.buffer)
        else:
            pass   # drop silently
        self.buffer = []

# Example
sampler = TailSampler(base_rate=0.1, error_rate=1.0, slow_threshold_ms=3000)
tracer = BufferedTracer(sampler)

for scenario in [
    {"has_error": True,  "duration_ms": 800,  "label": "error trace"},
    {"has_error": False, "duration_ms": 4500, "label": "slow trace"},
    {"has_error": False, "duration_ms": 400,  "label": "fast successful trace"},
]:
    tracer.record({"name": "agent_run", "duration_ms": scenario["duration_ms"]})
    tracer.record({"name": "llm_call",  "duration_ms": 300})
    tracer.finish_trace(scenario["has_error"], scenario["duration_ms"])
    decision = sampler.decide(scenario["has_error"], scenario["duration_ms"])
    print(f"  [{scenario['label']}] → {decision.reason}")
